mapper.update:
		/*
             SQL ID : CrsHomeDAO.updateEvalCriteriaScoreRatio
             설  명 : 평가기준 성적반영비율 수정
         */


				UPDATE TB_LMS_ASMT
				SET
					  MRK_RFLTRT = #{scoreRatio}
					, MDFR_ID			= #{mdfrId}
					, MOD_DTTM			= FN_DTTM()
				WHERE ASMT_ID = #{asmntCd}


				UPDATE TB_LMS_DSCS
				SET
					  MRK_RFLTRT = #{scoreRatio}
					, MDFR_ID			= #{mdfrId}
					, MOD_DTTM			= FN_DTTM()
				WHERE DSCS_ID = #{forumCd} 


				UPDATE TB_LMS_EXAM_BSC
				SET
					  MRK_RFLTRT = #{scoreRatio}
					, MDFR_ID			= #{mdfrId}
					, MOD_DTTM			= FN_DTTM()
				WHERE EXAM_ID = #{examCd}
				AND EXAM_CTGRCD = 'EXAM'


				UPDATE TB_LMS_EXAM_BSC
				SET
					  MRK_RFLTRT = #{scoreRatio}
					, MDFR_ID			= #{mdfrId}
					, MOD_DTTM			= FN_DTTM()
				WHERE EXAM_ID = #{examCd}
				AND EXAM_CTGRCD = 'QUIZ'


				UPDATE TB_LMS_SRVY
				SET
					  MRK_RFLTRT = #{scoreRatio}
					, MDFR_ID			= #{mdfrId}
					, MOD_DTTM			= FN_DTTM()
				WHERE SRVY_ID = #{reschCd}

mapper.select:
/* SQL ID : CrsHomeDAO.selectCrsHomeStdJoinStatus 설 명 : 강의실 홈 학습요소 참여현황 */ SELECT NVL(MAX(CASE WHEN GBN = 'ATTEND' THEN CNT END), 0) AS ATTEND_CNT , NVL(MAX(CASE WHEN GBN = 'ATTEND' THEN JOIN_CNT END), 0) AS ATTEND_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_ABSENT' THEN CNT END), 0) AS EXAM_ABSENT_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_ABSENT' THEN JOIN_CNT END), 0) AS EXAM_ABSENT_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'QUIZ' THEN CNT END), 0) AS QUIZ_CNT , NVL(MAX(CASE WHEN GBN = 'QUIZ' THEN JOIN_CNT END), 0) AS QUIZ_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'RESCH' THEN CNT END), 0) AS RESCH_CNT , NVL(MAX(CASE WHEN GBN = 'RESCH' THEN JOIN_CNT END), 0) AS RESCH_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'ASMNT' THEN CNT END), 0) AS ASMNT_CNT , NVL(MAX(CASE WHEN GBN = 'ASMNT' THEN JOIN_CNT END), 0) AS ASMNT_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'PRCT_ASMNT' THEN CNT END), 0) AS PRCT_ASMNT_CNT , NVL(MAX(CASE WHEN GBN = 'PRCT_ASMNT' THEN JOIN_CNT END), 0) AS PRCT_ASMNT_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'INS_EXAM' THEN CNT END), 0) AS INS_EXAM_CNT , NVL(MAX(CASE WHEN GBN = 'INS_EXAM' THEN JOIN_CNT END), 0) AS INS_EXAM_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'FORUM' THEN CNT END), 0) AS FORUM_CNT , NVL(MAX(CASE WHEN GBN = 'FORUM' THEN JOIN_CNT END), 0) AS FORUM_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'SEMINAR' THEN CNT END), 0) AS SEMINAR_CNT , NVL(MAX(CASE WHEN GBN = 'SEMINAR' THEN JOIN_CNT END), 0) AS SEMINAR_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'ALWAYS_EXAM' THEN CNT END), 0) AS ALWAYS_EXAM_CNT , NVL(MAX(CASE WHEN GBN = 'ALWAYS_EXAM' THEN JOIN_CNT END), 0) AS ALWAYS_EXAM_JOIN_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_DSBL_REQ' THEN CNT END), 0) AS EXAM_DSBL_REQ_CNT , NVL(MAX(CASE WHEN GBN = 'EXAM_DSBL_REQ' THEN JOIN_CNT END), 0) AS EXAM_DSBL_REQ_APPROVE_CNT , NVL(MAX(CASE WHEN GBN = 'SCORE_OBJT' THEN CNT END), 0) AS SCORE_OBJT_CNT , NVL(MAX(CASE WHEN GBN = 'SCORE_OBJT' THEN JOIN_CNT END), 0) AS SCORE_OBJT_PROC_CNT FROM ( -- 출결 SELECT 'ATTEND' AS GBN , COUNT(1) AS CNT , NVL(SUM(CASE WHEN B.ATNDLC_STSCD IN('COMPLETE', 'LATE') THEN 1 ELSE 0 END), 0) AS JOIN_CNT FROM TB_LMS_SBJCT_LCTR_SCHDL A LEFT JOIN TB_LMS_LESSON_STUDY_STATE B ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND B.STD_ID = #{stdId} WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd} AND A.LCTR_SCHDL_ID IN (
#{item}
''
) -- 결시원 UNION ALL SELECT 'EXAM_ABSENT' AS GBN , COUNT(1) AS CNT , NVL(SUM(CASE WHEN A.APRV_STSCD = 'APPROVE' THEN 1 ELSE 0 END), 0) AS JOIN_CNT FROM TB_LMS_EXAM_ABSNCE A WHERE A.SBJCT_ID = #{crsCreCd} AND A.STD_ID = #{stdId} -- 퀴즈 UNION ALL SELECT 'QUIZ' AS GBN , COUNT(1) AS CNT , COUNT(C.STD_ID) AS JOIN_CNT FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} LEFT JOIN TB_LMS_EXAM_STARE C ON A.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' AND C.STARE_CNT > 0 AND TO_DATE(C.SDTTM, 'YYYYMMDDHH24MISS') + NUMTODSINTERVAL((SELECT TKEXAM_MNTS FROM TB_LMS_EXAM_BSC WHERE EXAM_ID = A.EXAM_ID), 'MINUTE') < SYSDATE AND C.STD_ID = #{stdId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND A.EXAM_CTGRCD = 'QUIZ' AND A.TKEXAM_TYCD = 'A' AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.EXAM_ID ) AND FN_DTTM() >= A.EXAM_SDTTM -- 설문 UNION ALL SELECT 'RESCH' AS GBN , COUNT(1) AS CNT , COUNT(C.STD_ID) AS JOIN_CNT FROM TB_LMS_SRVY A JOIN TB_LMS_RESCH_CRE_CRS_RLTN B ON A.SRVY_ID = B.SRVY_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} LEFT JOIN TB_LMS_SRVY_PTCP C ON A.SRVY_ID = C.SRVY_ID AND C.STD_ID = #{stdId} AND C.USER_ID = #{userId} AND EXISTS(SELECT 1 FROM TB_LMS_SRVY_RSPNS WHERE USER_ID = C.USER_ID AND SRVY_ID = C.SRVY_ID) WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SRVY_QSTNS_CMPTNYN = 'Y' AND A.SRVY_TMPLTYN = 'N' AND FN_DTTM() >= A.SRVY_SDTTM -- 과제 UNION ALL SELECT 'ASMNT' AS GBN , COUNT(1) AS CNT , SUM(CASE WHEN UPPER(C.SBMSN_STSCD) IN ('SUBMIT', 'RE', 'LATE') THEN 1 ELSE 0 END) AS JOIN_CNT FROM TB_LMS_ASMT A JOIN TB_LMS_ASMNT_CRE_CRS_RLTN B ON A.ASMT_ID = B.ASMT_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} LEFT JOIN TB_LMS_ASMT_SBMSN C ON A.ASMT_ID = C.ASMT_ID AND C.DELYN = 'N' AND C.STD_ID = #{stdId} WHERE A.DELYN = 'N' AND A.ASMNT_OPEN_YN = 'Y' AND ( A.IND_YN = 'N' OR (A.IND_YN = 'Y' AND C.ASMT_SBMSN_ID IS NOT NULL) ) AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.ASMT_ID ) -- AND A.PRTC_YN = 'N' -- 실기과제 제외 CNT (실기과제 제외 삭제로 변경 2024.1.16) AND FN_DTTM() >= A.SEND_START_DTTM -- 실기과제 UNION ALL SELECT 'PRCT_ASMNT' AS GBN , COUNT(1) AS CNT , NVL(SUM(CASE WHEN UPPER(C.SBMSN_STSCD) IN ('SUBMIT', 'RE', 'LATE') THEN 1 ELSE 0 END), 0) AS JOIN_CNT FROM TB_LMS_ASMT A JOIN TB_LMS_ASMNT_CRE_CRS_RLTN B ON A.ASMT_ID = B.ASMT_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} LEFT JOIN TB_LMS_ASMT_SBMSN C ON A.ASMT_ID = C.ASMT_ID AND C.DELYN = 'N' AND C.STD_ID = #{stdId} WHERE A.DELYN = 'N' AND A.ASMNT_OPEN_YN = 'Y' AND A.PRTC_YN = 'Y' AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.ASMT_ID ) AND FN_DTTM() >= A.SEND_START_DTTM -- 대체평가 UNION ALL SELECT 'INS_EXAM' AS GBN , COUNT(1) AS CNT , SUM(JOIN_CNT) AS JOIN_CNT FROM ( SELECT A.EXAM_ID , CASE WHEN EXISTS (SELECT 1 FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = A.EXAM_ID AND DELYN = 'N' AND STD_ID = #{stdId} AND STARE_CNT > 0 AND SDTTM IS NOT NULL) THEN 1 -- 실시간 시험 참여수 WHEN EXISTS (SELECT 1 FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = A.EXAM_SBST_REF_ID AND DELYN = 'N' AND STD_ID = #{stdId} AND STARE_CNT > 0 AND SDTTM IS NOT NULL) THEN 1 -- 퀴즈 참여수 WHEN EXISTS (SELECT 1 FROM TB_LMS_ASMT_SBMSN WHERE ASMT_ID = A.EXAM_SBST_REF_ID AND DELYN = 'N' AND STD_ID = #{stdId} AND SBMSN_STSCD IN ('SUBMIT', 'RE', 'LATE')) THEN 1 -- 과제 참여수 WHEN EXISTS (SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = A.EXAM_SBST_REF_ID AND DELYN = 'N' AND STD_ID = #{stdId}) OR EXISTS (SELECT 1 FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = A.EXAM_SBST_REF_ID AND DELYN = 'N' AND STD_ID = #{stdNo}) THEN 1 -- 토론 참여수 ELSE 0 END AS JOIN_CNT FROM ( -- 실시간 시험 SELECT A.EXAM_ID , A.EXAM_SBST_REF_ID FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.TKEXAM_TYCD IN ('M', 'L') AND A.EXAM_TYCD = 'EXAM' AND FN_DTTM() >= A.EXAM_SDTTM UNION ALL -- 결시원 대체평가 SELECT A.EXAM_ID , A.EXAM_SBST_REF_ID FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.TKEXAM_TYCD IN ('M', 'L') AND A.EXAM_TYCD = 'EXAM' AND A.EXAM_SBST_REF_ID IS NOT NULL AND EXISTS( SELECT 1 FROM TB_LMS_EXAM_ABSNCE WHERE SBJCT_ID = B.SBJCT_ID AND EXAM_ID = A.EXAM_ID AND STD_ID = #{stdId} AND UPPER(APRV_STSCD) = 'APPROVE' ) AND FN_DTTM() >= A.EXAM_SDTTM -- 대체시험 UNION ALL SELECT A.EXAM_ID , A.EXAM_SBST_REF_ID FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.TKEXAM_TYCD IN ('M', 'L') AND A.EXAM_TYCD != 'EXAM' AND A.EXAM_SBST_REF_ID IS NOT NULL AND FN_DTTM() >= A.EXAM_SDTTM ) A ) A UNION ALL -- 토론 SELECT 'FORUM' AS GBN , COUNT(1) AS CNT , SUM(CASE WHEN EXISTS(SELECT DSCS_ID FROM TB_LMS_DSCS_ATCL WHERE DELYN = 'N' AND DSCS_ID = A.DSCS_ID AND STD_ID = #{stdId}) OR EXISTS(SELECT DSCS_ID FROM TB_LMS_DSCS_CMNT WHERE DELYN = 'N' AND DSCS_ID = A.DSCS_ID AND STD_ID = #{stdId}) THEN 1 ELSE 0 END) AS JOIN_CNT FROM TB_LMS_DSCS A JOIN TB_LMS_FORUM_CRE_CRS_RLTN B ON A.DSCS_ID = B.DSCS_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} WHERE A.DELYN = 'N' AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.DSCS_ID ) AND FN_DTTM() >= A.DSCS_SDTTM -- 세미나 UNION ALL SELECT 'SEMINAR' AS GBN , COUNT(1) AS CNT , NVL(SUM(CASE WHEN B.ATND_STSCD IN ('ATTEND', 'LATE') THEN 1 ELSE 0 END), 0) AS JOIN_CNT FROM TB_LMS_SMNR A LEFT JOIN TB_LMS_SMNR_ATND B ON A.SMNR_ID = B.SMNR_ID AND B.STD_ID = #{stdId} WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd} AND FN_DTTM() >= A.SMNR_SDTTM -- 시험 UNION ALL SELECT 'ALWAYS_EXAM' AS GBN , COUNT(1) AS CNT , COUNT(C.STD_ID) AS JOIN_CNT FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} LEFT JOIN TB_LMS_EXAM_STARE C ON A.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' AND C.STARE_CNT > 0 AND C.STD_ID = #{stdId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN = 'Y' AND A.EXAM_CTGRCD = 'EXAM' AND A.TKEXAM_TYCD = 'A' AND FN_DTTM() >= A.EXAM_SDTTM -- 장애인 지원 UNION ALL SELECT 'EXAM_DSBL_REQ' AS GBN , COUNT(1) * 2 AS CNT , SUM(CASE WHEN A.MID_APPR_STAT = 'APPROVE' THEN 1 ELSE 0 END) + SUM(CASE WHEN A.APRV_STSCD = 'APPROVE' THEN 1 ELSE 0 END) AS JOIN_CNT FROM TB_LMS_EXAM_SPRT_APLY A WHERE A.SBJCT_ID = #{crsCreCd} AND A.STD_ID = #{stdId} -- 이의신청 UNION ALL SELECT 'SCORE_OBJT' AS GBN , COUNT(1) AS CNT1 , SUM(CASE WHEN A.CHG_PROC_CD IS NOT NULL THEN 1 ELSE 0 END) AS CNT2 FROM MRK_OBJCT_APLY A WHERE A.SBJCT_ID = #{crsCreCd} AND A.STD_ID = #{stdId} ) A

/* SQL ID : CrsHomeDAO.listCrsHomeAsmnt 설 명 : 강의실 홈 주차 과제 목록 */ SELECT A.LCTR_SCHDL_ID , A.ASMT_ID , A.ASMT_TTL , A.SEND_START_DTTM , A.SEND_END_DTTM , A.EXT_SEND_DTTM , A.MRK_OYN , A.ASMNT_END_DTTM FROM ( SELECT A.LCTR_SCHDL_ID , B.ASMT_ID , B.ASMT_TTL , B.SEND_START_DTTM , B.SEND_END_DTTM , B.EXT_SEND_DTTM , B.MRK_OYN , B.ASMNT_END_DTTM , B.FRST_INQ_DTTM FROM ( SELECT A.LCTR_SCHDL_ID , A.LCTR_SYMD , A.LCTR_EYMD FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY A.GROUP_SEQ ORDER BY A.LCTR_SCHDL_SEQ) AS RN , A.LCTR_SCHDL_ID , A.LCTR_SYMD , A.LCTR_EYMD FROM ( SELECT A.LCTR_SCHDL_ID , A.LCTR_SYMD , A.LCTR_EYMD , A.LCTR_SCHDL_SEQ , ( SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE LCTR_EYMD < A.LCTR_SYMD AND SBJCT_ID = A.SBJCT_ID AND DELYN = 'N' ) + 1 AS GROUP_SEQ FROM TB_LMS_SBJCT_LCTR_SCHDL A WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd} ) A ) A WHERE A.RN = 1 ) A JOIN ( SELECT A.ASMT_ID , A.ASMT_TTL , A.SEND_START_DTTM , A.SEND_END_DTTM , A.EXT_SEND_DTTM , A.MRK_OYN , A.SEND_END_DTTM AS ASMNT_END_DTTM , A.FRST_INQ_DTTM -- , IF(A.EXT_SEND_ACPT_YN = 'Y' AND A.EXT_SEND_DTTM IS NOT NULL AND A.EXT_SEND_DTTM > A.SEND_END_DTTM, A.EXT_SEND_DTTM, A.SEND_END_DTTM) AS ASMNT_END_DTTM FROM TB_LMS_ASMT A JOIN TB_LMS_ASMNT_CRE_CRS_RLTN B ON A.ASMT_ID = B.ASMT_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd}
LEFT JOIN TB_LMS_ASMT_SBMSN C ON A.ASMT_ID = C.ASMT_ID AND C.DELYN = 'N' AND C.STD_ID = #{stdId}
WHERE A.DELYN = 'N' AND A.LCTR_SCHDL_ID IS NULL
AND ( A.IND_YN = 'N' OR (A.IND_YN = 'Y' AND C.ASMT_SBMSN_ID IS NOT NULL) ) AND A.SEND_START_DTTM <= FN_DTTM() AND A.ASMNT_OPEN_YN = 'Y'
-- 대체시험 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.ASMT_ID ) ) B
ON SUBSTR(B.SEND_START_DTTM, 1, 8) BETWEEN A.LCTR_SYMD AND A.LCTR_EYMD UNION ALL SELECT A.LCTR_SCHDL_ID , A.ASMT_ID , A.ASMT_TTL , A.SEND_START_DTTM , A.SEND_END_DTTM , A.EXT_SEND_DTTM , A.MRK_OYN , A.SEND_END_DTTM AS ASMNT_END_DTTM , A.FRST_INQ_DTTM -- , IF(A.EXT_SEND_ACPT_YN = 'Y' AND A.EXT_SEND_DTTM IS NOT NULL AND A.EXT_SEND_DTTM > A.SEND_END_DTTM, A.EXT_SEND_DTTM, A.SEND_END_DTTM) AS ASMNT_END_DTTM FROM TB_LMS_ASMT A JOIN TB_LMS_ASMNT_CRE_CRS_RLTN B ON A.ASMT_ID = B.ASMT_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd}
LEFT JOIN TB_LMS_ASMT_SBMSN C ON A.ASMT_ID = C.ASMT_ID AND C.DELYN = 'N' AND C.STD_ID = #{stdId}
WHERE A.DELYN = 'N' AND A.LCTR_SCHDL_ID IS NOT NULL
AND ( A.IND_YN = 'N' OR (A.IND_YN = 'Y' AND C.ASMT_SBMSN_ID IS NOT NULL) ) AND A.SEND_START_DTTM <= FN_DTTM() AND A.ASMNT_OPEN_YN = 'Y'
-- 대체시험 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.ASMT_ID ) ) A ORDER BY A.SEND_START_DTTM, A.FRST_INQ_DTTM

/* SQL ID : CrsHomeDAO.listCrsHomeQuiz 설 명 : 강의실 홈 주차 퀴즈 목록 */ SELECT A.LCTR_SCHDL_ID , A.EXAM_ID , A.EXAM_TTL , A.EXAM_SDTTM , A.EXAM_EDTTM , A.MRK_OYN , A.RE_YN
, CASE WHEN (SELECT TO_DATE(AA.SDTTM, 'YYYYMMDDHH24MISS') + NUMTODSINTERVAL((SELECT BB.TKEXAM_MNTS FROM TB_LMS_EXAM_BSC BB WHERE BB.EXAM_ID = A.EXAM_ID), 'MINUTE') FROM TB_LMS_EXAM_STARE AA WHERE AA.EXAM_ID = A.EXAM_ID AND AA.STD_ID = #{stdId}) < SYSDATE THEN 'Y' ELSE 'N' END AS STARE_YN
FROM ( SELECT A.LCTR_SCHDL_ID , B.EXAM_ID , B.EXAM_TTL , B.EXAM_SDTTM , B.EXAM_EDTTM , B.MRK_OYN , B.RE_YN , B.FRST_INQ_DTTM FROM ( SELECT A.LCTR_SCHDL_ID , A.LCTR_SYMD , A.LCTR_EYMD FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY A.GROUP_SEQ ORDER BY A.LCTR_SCHDL_SEQ) AS RN , A.LCTR_SCHDL_ID , A.LCTR_SYMD , A.LCTR_EYMD FROM ( SELECT A.LCTR_SCHDL_ID , A.LCTR_SYMD , A.LCTR_EYMD , A.LCTR_SCHDL_SEQ , ( SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE LCTR_EYMD < A.LCTR_SYMD AND SBJCT_ID = A.SBJCT_ID AND DELYN = 'N' ) + 1 AS GROUP_SEQ FROM TB_LMS_SBJCT_LCTR_SCHDL A WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd} ) A ) A WHERE A.RN = 1 ) A JOIN ( SELECT A.EXAM_ID , A.EXAM_TTL , A.EXAM_SDTTM , A.EXAM_EDTTM , A.MRK_OYN , 'N' AS RE_YN , A.FRST_INQ_DTTM FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND A.EXAM_CTGRCD = 'QUIZ' AND A.TKEXAM_TYCD = 'A' AND A.LCTR_SCHDL_ID IS NULL -- 대체시험 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.EXAM_ID )
-- 재응시 대상자 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = A.EXAM_ID AND DELYN = 'N' AND REEXAMYN = 'Y' AND STD_ID = #{stdId} )
-- 재응시 퀴즈 UNION ALL SELECT A.EXAM_ID , A.EXAM_TTL , A.RE_EXAM_START_DTTM AS EXAM_SDTTM , A.RE_EXAM_END_DTTM AS EXAM_EDTTM , A.MRK_OYN , 'Y' AS RE_YN , A.FRST_INQ_DTTM FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} JOIN TB_LMS_EXAM_STARE C ON A.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' AND C.REEXAMYN = 'Y' AND C.STD_ID = #{stdId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND A.EXAM_CTGRCD = 'QUIZ' AND A.TKEXAM_TYCD = 'A' AND A.LCTR_SCHDL_ID IS NULL -- 대체시험 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.EXAM_ID ) AND A.REEXAMYN = 'Y'
) B
ON SUBSTR(B.EXAM_SDTTM, 1, 8) BETWEEN A.LCTR_SYMD AND A.LCTR_EYMD UNION ALL SELECT A.LCTR_SCHDL_ID , A.EXAM_ID , A.EXAM_TTL , A.EXAM_SDTTM , A.EXAM_EDTTM , A.MRK_OYN , 'N' AS RE_YN , A.FRST_INQ_DTTM FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND A.EXAM_CTGRCD = 'QUIZ' AND A.TKEXAM_TYCD = 'A' AND A.LCTR_SCHDL_ID IS NOT NULL -- 대체시험 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.EXAM_ID )
-- 재응시 대상자 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = A.EXAM_ID AND DELYN = 'N' AND REEXAMYN = 'Y' AND STD_ID = #{stdId} )
-- 재응시 퀴즈 UNION ALL SELECT A.LCTR_SCHDL_ID , A.EXAM_ID , A.EXAM_TTL , A.RE_EXAM_START_DTTM AS EXAM_SDTTM , A.RE_EXAM_END_DTTM AS EXAM_EDTTM , A.MRK_OYN , 'Y' AS RE_YN , A.FRST_INQ_DTTM FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} JOIN TB_LMS_EXAM_STARE C ON A.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' AND C.REEXAMYN = 'Y' AND C.STD_ID = #{stdId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND A.EXAM_CTGRCD = 'QUIZ' AND A.TKEXAM_TYCD = 'A' AND A.LCTR_SCHDL_ID IS NOT NULL -- 대체시험 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.EXAM_ID ) AND A.REEXAMYN = 'Y'
) A ORDER BY A.EXAM_SDTTM, A.FRST_INQ_DTTM

/* SQL ID : CrsHomeDAO.listCrsHomeResch 설 명 : 강의실 홈 주차 설문 목록 */ SELECT A.LCTR_SCHDL_ID , B.SRVY_ID , B.SRVY_TTL , B.SRVY_CTGRCD , B.SRVY_TYCD , B.SRVY_SDTTM , B.RESCH_END_DTTM , B.RESCH_RSLT_TYPE_NM
, B.RESCH_JOIN_YN
FROM ( SELECT A.LCTR_SCHDL_ID , A.LCTR_SYMD , A.LCTR_EYMD FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY A.GROUP_SEQ ORDER BY A.LCTR_SCHDL_SEQ) AS RN , A.LCTR_SCHDL_ID , A.LCTR_SYMD , A.LCTR_EYMD FROM ( SELECT A.LCTR_SCHDL_ID , A.LCTR_SYMD , A.LCTR_EYMD , A.LCTR_SCHDL_SEQ , ( SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE LCTR_EYMD < A.LCTR_SYMD AND SBJCT_ID = A.SBJCT_ID AND DELYN = 'N' ) + 1 AS GROUP_SEQ FROM TB_LMS_SBJCT_LCTR_SCHDL A WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd} ) A ) A WHERE A.RN = 1 ) A JOIN ( SELECT A.SRVY_ID , A.SRVY_TTL , A.SRVY_CTGRCD , A.SRVY_TYCD , A.SRVY_SDTTM , A.RESCH_END_DTTM , ( SELECT NVL(BB.CDNM, AA.CDNM) FROM TB_ORG_CODE AA LEFT JOIN TB_ORG_CODE_LANG BB ON AA.ORG_ID = BB.ORG_ID AND AA.CTGRCD = BB.CTGRCD AND AA.CD = BB.CD AND BB.LANG_CD = #{langCd} WHERE AA.ORG_ID = A.ORG_ID AND AA.CTGRCD = 'RSLT_OPEN_TYCD' AND AA.CD = A.RSLT_OPEN_TYCD ) AS RESCH_RSLT_TYPE_NM
, CASE WHEN C.SRVY_ID IS NOT NULL THEN 'Y' ELSE 'N' END AS RESCH_JOIN_YN
FROM TB_LMS_SRVY A JOIN TB_LMS_RESCH_CRE_CRS_RLTN B ON A.SRVY_ID = B.SRVY_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd}
LEFT JOIN TB_LMS_SRVY_PTCP C ON A.SRVY_ID = C.SRVY_ID AND C.USER_ID = #{userId} AND C.STD_ID = #{stdId} AND EXISTS(SELECT 1 FROM TB_LMS_SRVY_RSPNS WHERE USER_ID = C.USER_ID AND SRVY_ID = C.SRVY_ID)
WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SRVY_TMPLTYN = 'N' AND A.SRVY_QSTNS_CMPTNYN = 'Y'
AND A.SRVY_TYCD NOT IN ('EVAL', 'LEVEL')
) B
ON SUBSTR(B.SRVY_SDTTM, 1, 8) BETWEEN A.LCTR_SYMD AND A.LCTR_EYMD ORDER BY B.SRVY_SDTTM

/* SQL ID : CrsHomeDAO.crsHomeScheduleListStatus 설 명 : 강의실 홈 학생 참여현황 */ WITH GBN_T AS ( SELECT 'LESSON_SCHEDULE' AS GBN FROM DUAL UNION ALL SELECT 'LESSON_CNTS' FROM DUAL UNION ALL SELECT 'AEXAM' FROM DUAL UNION ALL SELECT 'ASMNT' FROM DUAL UNION ALL SELECT 'FORUM' FROM DUAL UNION ALL SELECT 'QUIZ' FROM DUAL UNION ALL SELECT 'RESCH' FROM DUAL UNION ALL SELECT 'SEMINAR' FROM DUAL ), STD_T AS ( SELECT A.STD_ID FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_USER_ACNT B ON A.USER_ID = B.USER_ID WHERE A.SBJCT_ID = #{crsCreCd} AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'N' AND B.ACNT_STSCD = 'U' ), STD_CNT_T AS ( SELECT COUNT(*) AS STD_CNT FROM STD_T ) SELECT A.GBN, STD_CNT.STD_CNT
, LESSON_SCHEDULE.LCTR_SCHDL_ID , LESSON_SCHEDULE.LESSON_SCHEDULE_COMPLETE_CNT , LESSON_SCHEDULE.LESSON_SCHEDULE_LATE_CNT , LESSON_SCHEDULE.LESSON_SCHEDULE_JOIN_RATE
FROM GBN_T A CROSS JOIN STD_CNT_T STD_CNT
LEFT JOIN ( SELECT 'LESSON_SCHEDULE' AS GBN, A.LCTR_SCHDL_ID, A.LESSON_SCHEDULE_COMPLETE_CNT, A.LESSON_SCHEDULE_LATE_CNT, NVL(ROUND((A.LESSON_SCHEDULE_COMPLETE_CNT + A.LESSON_SCHEDULE_LATE_CNT) / NULLIF(STD_CNT.STD_CNT, 0) * 100, 2), 0) AS LESSON_SCHEDULE_JOIN_RATE FROM ( SELECT A.LCTR_SCHDL_ID, NVL(SUM(CASE WHEN B.ATNDLC_STSCD = 'COMPLETE' THEN 1 ELSE 0 END), 0) AS LESSON_SCHEDULE_COMPLETE_CNT, NVL(SUM(CASE WHEN B.ATNDLC_STSCD = 'LATE' THEN 1 ELSE 0 END), 0) AS LESSON_SCHEDULE_LATE_CNT FROM TB_LMS_SBJCT_LCTR_SCHDL A LEFT JOIN TB_LMS_LESSON_STUDY_STATE B ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND B.STD_ID IN (SELECT STD_ID FROM STD_T) WHERE A.LCTR_SCHDL_ID IN (
#{item}
) GROUP BY A.LCTR_SCHDL_ID ) A, STD_CNT_T STD_CNT ) LESSON_SCHEDULE ON A.GBN = LESSON_SCHEDULE.GBN
LEFT JOIN ( SELECT 'LESSON_CNTS' AS GBN, A.SBJCT_LCTR_CONTS_ID, COUNT(B.SBJCT_LCTR_CONTS_ID) AS LESSON_CNTS_JOIN_CNT FROM TB_LMS_SBJCT_LCTR_CONTS A LEFT JOIN TB_LMS_LESSON_STUDY_RECORD B ON A.SBJCT_LCTR_CONTS_ID = B.SBJCT_LCTR_CONTS_ID AND B.STD_ID IN (SELECT STD_ID FROM STD_T) WHERE A.SBJCT_LCTR_CONTS_ID IN (
#{item}
) GROUP BY A.SBJCT_LCTR_CONTS_ID ) LESSON_CNTS ON A.GBN = LESSON_CNTS.GBN
LEFT JOIN ( SELECT 'AEXAM' AS GBN, A.EXAM_ID, COUNT(B.EXAM_ID) AS EXAM_JOIN_CNT FROM TB_LMS_EXAM_BSC A LEFT JOIN TB_LMS_EXAM_STARE B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.STARE_CNT > 0 AND B.STD_ID IN (SELECT STD_ID FROM STD_T) WHERE A.EXAM_ID IN (
#{item}
) GROUP BY A.EXAM_ID ) AEXAM ON A.GBN = AEXAM.GBN
LEFT JOIN ( SELECT 'ASMNT' AS GBN, A.ASMT_ID, SUM(CASE WHEN UPPER(B.SBMSN_STSCD) IN ('SUBMIT', 'RE') THEN 1 ELSE 0 END) AS ASMNT_SUBMIT_CNT, SUM(CASE WHEN UPPER(B.SBMSN_STSCD) = 'LATE' THEN 1 ELSE 0 END) AS ASMNT_LATE_CNT, CASE WHEN A.IND_YN = 'Y' THEN COUNT(B.ASMT_SBMSN_ID) ELSE NULL END AS ASMNT_IND_STD_CNT FROM TB_LMS_ASMT A LEFT JOIN TB_LMS_ASMT_SBMSN B ON A.ASMT_ID = B.ASMT_ID AND B.DELYN = 'N' AND B.STD_ID IN (SELECT STD_ID FROM STD_T) WHERE A.ASMT_ID IN (
#{item}
) GROUP BY A.ASMT_ID, A.IND_YN ) ASMNT ON A.GBN = ASMNT.GBN
LEFT JOIN ( SELECT 'FORUM' AS GBN, A.DSCS_ID, COUNT(DISTINCT S.STD_ID) AS FORUM_JOIN_CNT FROM TB_LMS_DSCS A JOIN TB_LMS_DSCS_ATCL B ON A.DSCS_ID = B.DSCS_ID JOIN TB_LMS_ATNDLC_SBJCT S ON S.STD_ID = B.STD_ID LEFT JOIN TB_LMS_DSCS_CMNT C ON S.STD_ID = C.STD_ID WHERE A.DSCS_ID IN (
#{item}
) AND S.ATNDLC_STSCD = 'S' AND (B.DELYN = 'N' OR C.DELYN = 'N') GROUP BY A.DSCS_ID ) FORUM ON A.GBN = FORUM.GBN
LEFT JOIN ( SELECT 'QUIZ' AS GBN, A.EXAM_ID AS QUIZ_CD, SUM(CASE WHEN B.REEXAMYN != 'Y' THEN 1 ELSE 0 END) AS QUIZ_JOIN_CNT, SUM(CASE WHEN B.REEXAMYN = 'Y' THEN 1 ELSE 0 END) AS QUIZ_RE_JOIN_CNT FROM TB_LMS_EXAM_BSC A LEFT JOIN TB_LMS_EXAM_STARE B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.STARE_CNT > 0 AND B.SDTTM IS NOT NULL AND B.EDTTM IS NOT NULL AND B.STD_ID IN (SELECT STD_ID FROM STD_T) WHERE A.EXAM_ID IN (
#{item}
) GROUP BY A.EXAM_ID ) QUIZ ON A.GBN = QUIZ.GBN
LEFT JOIN ( SELECT 'RESCH' AS GBN, A.SRVY_ID, COUNT(B.STD_ID) AS RESCH_JOIN_CNT FROM TB_LMS_SRVY A LEFT JOIN TB_LMS_SRVY_PTCP B ON A.SRVY_ID = B.SRVY_ID AND B.STD_ID IN (SELECT STD_ID FROM STD_T) AND EXISTS ( SELECT 1 FROM TB_LMS_SRVY_RSPNS WHERE USER_ID = B.USER_ID AND SRVY_ID = B.SRVY_ID ) WHERE A.SRVY_ID IN (
#{item}
) GROUP BY A.SRVY_ID ) RESCH ON A.GBN = RESCH.GBN
LEFT JOIN ( SELECT 'SEMINAR' AS GBN, A.SMNR_ID, A.SMNR_CTGRCD, SUM(CASE WHEN C.ATND_STSCD = 'ATTEND' THEN 1 ELSE 0 END) AS SEMINAR_ATTEND_CNT, SUM(CASE WHEN C.ATND_STSCD = 'LATE' THEN 1 ELSE 0 END) AS SEMINAR_LATE_CNT, SUM(CASE WHEN C.ATND_STSCD IN ('ABSENT', 'START') OR C.STD_ID IS NULL THEN 1 ELSE 0 END) AS SEMINAR_ABSENT_CNT FROM TB_LMS_SMNR A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' LEFT JOIN TB_LMS_SMNR_ATND C ON A.SMNR_ID = C.SMNR_ID AND B.STD_ID = C.STD_ID WHERE A.DELYN = 'N' AND A.SMNR_ID IN (
#{item}
) GROUP BY A.SMNR_ID, A.SMNR_CTGRCD ) SEMINAR ON A.GBN = SEMINAR.GBN
